<!doctype html>
<html lang="vi">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Quản Lý Nhân Khẩu Thôn 09</title>
  <link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css" rel="stylesheet">
  <link rel="preconnect" href="https://fonts.googleapis.com">
  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
  <link href="https://fonts.googleapis.com/css2?family=Be+Vietnam+Pro:wght@400;500;600;700&display=swap" rel="stylesheet">
  <link href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.2/css/all.min.css" rel="stylesheet">
  <link rel="stylesheet" href="assets/css/app.css?v=20260629-dashboard-minimal-1">
</head>
<body>
  <div id="toastHost" class="toast-container position-fixed top-0 end-0 p-3"></div>

  <main id="loginView" class="login-view">
    <section class="login-landing" aria-label="Đăng nhập hệ thống quản lý hành chính Thôn 09">
      <section class="login-panel" aria-labelledby="loginSystemName">
        <div class="login-brand" aria-label="Thôn 09 xã Hồng Phong">
          <div id="loginLogo" class="login-logo login-logo-emblem" aria-hidden="true">
            <span class="logo-flag"><i class="fa-solid fa-star"></i></span>
            <span class="logo-landmark"><i class="fa-solid fa-landmark"></i></span>
            <span class="logo-village"><i class="fa-solid fa-house-chimney"></i></span>
            <span class="logo-name">Thôn</span>
            <strong>09</strong>
          </div>
          <div class="login-title-block">
            <p id="loginSystemName">Hệ thống Quản lý Hành chính</p>
            <h1><span id="loginHamletName">Thôn 09</span> - <span id="loginCommuneName">Xã Hồng Phong</span></h1>
            <div id="loginSlogan" class="login-slogan">Vì Nhân dân phục vụ</div>
          </div>
        </div>
        <form id="loginForm" class="login-form" novalidate>
          <div class="login-field">
            <label class="form-label" for="loginEmail">Tên đăng nhập</label>
            <div class="login-input-wrap"><i class="fa-solid fa-user" aria-hidden="true"></i><input id="loginEmail" name="email" type="text" class="form-control" placeholder="Nhập tên đăng nhập" autocomplete="username" inputmode="email" required></div>
          </div>
          <div class="login-field">
            <label class="form-label" for="loginPassword">Mật khẩu</label>
            <div class="login-input-wrap"><i class="fa-solid fa-lock" aria-hidden="true"></i><input id="loginPassword" name="password" type="password" class="form-control" placeholder="Nhập mật khẩu" autocomplete="current-password" required minlength="8"><button class="password-toggle" type="button" aria-label="Hiện mật khẩu" data-password-toggle><i class="fa-solid fa-eye" aria-hidden="true"></i></button></div>
          </div>
          <button class="btn login-submit" type="submit"><i class="fa-solid fa-right-to-bracket" aria-hidden="true"></i><span>Đăng nhập</span></button>
        </form>
        <footer class="login-footer"><span id="loginVersion">Phiên bản v2.0</span><span id="loginCopyright">© Thôn 09 - Xã Hồng Phong</span></footer>
      </section>
    </section>
  </main>

  <div id="appView" class="app-shell d-none">
    <aside class="sidebar"><div class="sidebar-brand"><span class="state-mark small-mark">09</span><div><strong>Thôn 09</strong><small>xã Hồng Phong</small></div></div><nav class="nav flex-column gap-1"><button class="nav-link active" data-screen="dashboard">Tổng quan</button><button class="nav-link" data-screen="households">Hộ dân</button><button class="nav-link" data-screen="persons">Nhân khẩu</button><button class="nav-link" data-screen="reports">Báo cáo</button></nav></aside>

    <section class="main-area">
      <header class="topbar"><button id="sidebarToggle" class="btn btn-outline-secondary btn-sm d-lg-none" type="button">Menu</button><div><h2 id="screenTitle" class="h5 mb-0">Tổng quan</h2><small class="text-muted">Quản Lý Nhân Khẩu Thôn 09 xã Hồng Phong</small></div><div class="ms-auto text-end"><div id="currentUser" class="small text-muted"></div><button id="logoutBtn" class="btn btn-link btn-sm text-decoration-none px-0">Đăng xuất</button></div></header>
      <div id="loadingBar" class="progress rounded-0 d-none" style="height:3px"><div class="progress-bar progress-bar-striped progress-bar-animated w-100"></div></div>

      <section id="dashboardScreen" class="screen active dashboard-overview-screen">
        <section class="dashboard-hero-row">
          <div>
            <h2>Tổng quan</h2>
            <p>Theo dõi nhanh các chỉ số trọng tâm về hộ dân và nhân khẩu Thôn 09.</p>
          </div>
          <div id="dashboardGeneratedAt" class="dashboard-sync-note">Đang cập nhật dữ liệu</div>
        </section>
        <section id="dashboardKpis" class="dashboard-kpi-grid" aria-label="Chỉ số tổng quan"></section>
        <section class="dashboard-chart-grid" aria-label="Biểu đồ tổng quan">
          <article class="dashboard-panel dashboard-panel-large">
            <div class="dashboard-panel-head">
              <h3>Cơ cấu nhân khẩu theo độ tuổi</h3>
            </div>
            <div id="ageStructureChart" class="dashboard-chart-body"></div>
          </article>
          <article class="dashboard-panel dashboard-panel-large">
            <div class="dashboard-panel-head">
              <h3>Biến động nhân khẩu 6 tháng gần nhất</h3>
              <span class="dashboard-filter-pill">6 tháng</span>
            </div>
            <div id="populationMovementChart" class="dashboard-chart-body"></div>
          </article>
          <article class="dashboard-panel">
            <div class="dashboard-panel-head">
              <h3>Cơ cấu nhân khẩu theo giới tính</h3>
            </div>
            <div id="genderStructureChart" class="dashboard-chart-body"></div>
          </article>
          <article class="dashboard-panel">
            <div class="dashboard-panel-head">
              <h3>Đảng viên trên tổng nhân khẩu</h3>
            </div>
            <div id="partyMemberChart" class="dashboard-chart-body"></div>
          </article>
        </section>
      </section>

      <section id="householdsScreen"      <section id="householdsScreen" class="screen"><div class="toolbar"><input id="householdSearch" class="form-control" placeholder="Tìm mã hộ, chủ hộ, địa chỉ, điện thoại"><select id="householdPageSize" class="form-select w-auto"><option>20</option><option>50</option><option>100</option></select><button id="householdAddBtn" class="btn btn-primary">Thêm hộ dân</button><button id="householdBulkDeleteBtn" class="btn btn-outline-danger">Xóa đã chọn</button></div><div class="content-card table-responsive"><table class="table table-hover align-middle mb-0"><thead><tr><th><input type="checkbox" id="householdCheckAll"></th><th>Mã hộ</th><th>Chủ hộ</th><th>Địa chỉ</th><th>Ở nhà</th><th>Đi vắng</th><th>Diện hộ</th><th></th></tr></thead><tbody id="householdRows"></tbody></table></div><div id="householdPager" class="pager"></div></section>

      <section id="personsScreen" class="screen"><div class="content-card person-filter-card mb-3"><div class="row g-2 align-items-end"><div class="col-xl-4 col-lg-12"><label class="form-label">Tìm kiếm nhanh</label><input id="personSearch" class="form-control" placeholder="Họ tên, CCCD, mã nhân khẩu, số định danh cá nhân"></div><div class="col-xl-2 col-md-3 col-6"><label class="form-label">Giới tính</label><select class="form-select" data-person-filter="gender" name="gender"><option value="">Tất cả</option><option value="Nam">Nam</option><option value="Nữ">Nữ</option></select></div><div class="col-xl-2 col-md-3 col-6"><label class="form-label">Cư trú</label><select class="form-select" data-person-filter="residenceCombined" name="residenceCombined"><option value="">Tất cả</option><option value="PERMANENT">Thường trú</option><option value="TEMPORARY">Tạm trú</option><option value="AWAY">Tạm vắng</option></select></div><div class="col-xl-2 col-md-3 col-6"><label class="form-label">Đảng viên</label><select class="form-select" data-person-filter="party_member" name="party_member"><option value="">Tất cả</option><option value="1">Có</option><option value="0">Không</option></select></div><div class="col-xl-2 col-md-3 col-6"><label class="form-label">Độ tuổi</label><select class="form-select" data-person-filter="ageGroup" name="ageGroup"><option value="">Tất cả</option><option value="under6">Dưới 6 tuổi</option><option value="6_17">6-17 tuổi</option><option value="18_59">18-59 tuổi</option><option value="60_plus">Từ 60 tuổi trở lên</option></select></div><div class="col-lg-4 col-md-4"><label class="form-label">Nghề nghiệp</label><select class="form-select" data-person-filter="occupation" name="occupation" data-dictionary="occupations"><option value="">Tất cả</option></select></div><div class="col-lg-4 col-md-4"><label class="form-label">Dân tộc</label><select class="form-select" data-person-filter="ethnicity" name="ethnicity" data-dictionary="ethnicities"><option value="">Tất cả</option></select></div><div class="col-lg-4 col-md-4"><label class="form-label">Tôn giáo</label><select class="form-select" data-person-filter="religion" name="religion" data-dictionary="religions"><option value="">Tất cả</option></select></div><div class="col-12 d-flex justify-content-between align-items-center gap-2 flex-wrap person-filter-actions"><div class="d-flex align-items-center gap-2 flex-wrap"><select id="personPageSize" class="form-select w-auto"><option>20</option><option>50</option><option>100</option></select><button id="personAdvancedToggle" class="btn btn-outline-secondary" type="button" aria-expanded="false" aria-controls="personAdvancedFilters"><i class="fa-solid fa-sliders"></i> Bộ lọc nâng cao</button><button id="personFilterReset" class="btn btn-light" type="button">Xóa lọc</button></div><div class="d-flex align-items-center gap-2 flex-wrap"><button id="personAddBtn" class="btn btn-primary">Thêm nhân khẩu</button><button id="personBulkDeleteBtn" class="btn btn-outline-danger">Xóa đã chọn</button></div></div></div><div id="personAdvancedFilters" class="advanced-filter-panel d-none mt-3 pt-3 border-top"><div class="row g-2"><div class="col-lg-3 col-md-4"><label class="form-label">Đoàn viên Thanh niên</label><select class="form-select" data-person-filter="youth_union_member" name="youth_union_member"><option value="">Tất cả</option><option value="1">Có</option><option value="0">Không</option></select></div><div class="col-lg-3 col-md-4"><label class="form-label">Hội Phụ nữ</label><select class="form-select" data-person-filter="women_union_member" name="women_union_member"><option value="">Tất cả</option><option value="1">Có</option><option value="0">Không</option></select></div><div class="col-lg-3 col-md-4"><label class="form-label">Hội Nông dân</label><select class="form-select" data-person-filter="farmers_union_member" name="farmers_union_member"><option value="">Tất cả</option><option value="1">Có</option><option value="0">Không</option></select></div><div class="col-lg-3 col-md-4"><label class="form-label">Hội Cựu chiến binh</label><select class="form-select" data-person-filter="veterans_union_member" name="veterans_union_member"><option value="">Tất cả</option><option value="1">Có</option><option value="0">Không</option></select></div><div class="col-lg-3 col-md-4"><label class="form-label">Hội Người cao tuổi</label><select class="form-select" data-person-filter="elderly_union_member" name="elderly_union_member"><option value="">Tất cả</option><option value="1">Có</option><option value="0">Không</option></select></div><div class="col-lg-3 col-md-4"><label class="form-label">Người có công</label><select class="form-select" data-person-filter="meritorious_person" name="meritorious_person"><option value="">Tất cả</option><option value="1">Có</option><option value="0">Không</option></select></div><div class="col-lg-3 col-md-4"><label class="form-label">Người khuyết tật</label><select class="form-select" data-person-filter="disabled_person" name="disabled_person"><option value="">Tất cả</option><option value="1">Có</option><option value="0">Không</option></select></div><div class="col-lg-3 col-md-4"><label class="form-label">Bảo trợ xã hội</label><select class="form-select" data-person-filter="social_assistance" name="social_assistance"><option value="">Tất cả</option><option value="1">Có</option><option value="0">Không</option></select></div><div class="col-lg-3 col-md-4"><label class="form-label">Tình trạng hôn nhân</label><select class="form-select" data-person-filter="maritalStatus" name="maritalStatus" data-dictionary="maritalStatuses"><option value="">Tất cả</option></select></div><div class="col-lg-3 col-md-4"><label class="form-label">Trình độ học vấn</label><select class="form-select" data-person-filter="educationLevel" name="educationLevel" data-dictionary="educationLevels"><option value="">Tất cả</option></select></div><div class="col-lg-3 col-md-4"><label class="form-label">Nơi làm việc</label><input class="form-control" data-person-filter="workplace" name="workplace" placeholder="Nhập nơi làm việc"></div><div class="col-lg-3 col-md-4"><label class="form-label">Quốc tịch</label><input class="form-control" data-person-filter="nationality" name="nationality" placeholder="Nhập quốc tịch"></div><div class="col-lg-3 col-md-4"><label class="form-label">Nhóm máu</label><input class="form-control" data-person-filter="bloodType" name="bloodType" placeholder="A, B, AB, O..."></div></div></div></div><div class="content-card table-responsive"><table class="table table-hover align-middle mb-0"><thead><tr><th><input type="checkbox" id="personCheckAll"></th><th>Mã hộ</th><th>Mã nhân khẩu</th><th>Họ tên</th><th>Ngày sinh</th><th>CCCD</th><th>Thường trú</th><th>Hiện tại</th><th></th></tr></thead><tbody id="personRows"></tbody></table></div><div id="personPager" class="pager"></div></section>

      <section id="reportsScreen" class="screen">
        <form id="reportForm" class="content-card mb-3">
          <div class="row g-3 align-items-end">
            <div class="col-md-3"><label class="form-label">Loại báo cáo</label><select name="type" class="form-select"><option value="summary">Báo cáo tổng hợp</option><option value="household">Danh sách hộ dân</option><option value="population">Danh sách nhân khẩu</option><option value="gender">Theo giới tính</option><option value="age">Theo độ tuổi</option><option value="residency">Theo cư trú</option><option value="special">Người có công, hộ nghèo, cận nghèo, tàn tật</option><option value="movement">Biến động dân cư</option></select></div>
            <div class="col-md-2"><label class="form-label">Từ ngày</label><input name="dateFrom" type="date" class="form-control"></div>
            <div class="col-md-2"><label class="form-label">Đến ngày</label><input name="dateTo" type="date" class="form-control"></div>
            <div class="col-md-2"><label class="form-label">Cư trú</label><select name="residencyStatus" class="form-select"><option value="">Tất cả</option><option value="PERMANENT">Thường trú</option><option value="TEMPORARY">Tạm trú</option></select></div>
            <div class="col-md-2"><label class="form-label">Hiện tại</label><select name="presenceStatus" class="form-select"><option value="">Tất cả</option><option value="AT_HOME">Ở nhà</option><option value="AWAY">Đi vắng</option></select></div>
            <div class="col-md-2"><label class="form-label">Diện hộ</label><select name="household_type" class="form-select"><option value="">Tất cả</option><option>Hộ nghèo</option><option>Hộ cận nghèo</option><option>Hộ mới thoát nghèo</option><option>Hộ chính sách</option><option>Hộ có công</option><option>Hộ bình thường</option><option>Khác</option></select></div>
            <div class="col-md-2"><label class="form-label">Đảng viên</label><select name="party_member" class="form-select"><option value="">Tất cả</option><option value="1">Có</option><option value="0">Không</option></select></div>
            <div class="col-md-2"><label class="form-label">Đoàn viên</label><select name="youth_union_member" class="form-select"><option value="">Tất cả</option><option value="1">Có</option><option value="0">Không</option></select></div>
            <div class="col-md-2"><label class="form-label">Người có công</label><select name="meritorious_person" class="form-select"><option value="">Tất cả</option><option value="1">Có</option><option value="0">Không</option></select></div>
            <div class="col-md-2"><label class="form-label">Khuyết tật</label><select name="disabled_person" class="form-select"><option value="">Tất cả</option><option value="1">Có</option><option value="0">Không</option></select></div>
            <div class="col-md-1"><button class="btn btn-primary w-100" type="submit">Xem</button></div>
            <div class="col-12 d-flex justify-content-end gap-2"><button id="reportPrintBtn" class="btn btn-outline-secondary" type="button">In</button><button id="reportExcelBtn" class="btn btn-success" type="button">Xuất Excel</button><button id="reportPdfBtn" class="btn btn-outline-danger" type="button">Xuất PDF</button></div>
          </div>
        </form>
        <div class="content-card"><div class="d-flex justify-content-between align-items-center mb-3"><h3 id="reportTitle" class="section-title mb-0">Báo cáo</h3><span id="reportCount" class="text-muted small"></span></div><div id="reportPreview" class="table-responsive"><p class="text-muted mb-0">Chọn điều kiện và bấm Xem để xem trước báo cáo.</p></div></div>
      </section>
    </section>
  </div>

  <div class="modal fade" id="householdModal" tabindex="-1" aria-hidden="true"><div class="modal-dialog modal-lg modal-dialog-scrollable"><form class="modal-content" id="householdForm"><div class="modal-header"><h5 class="modal-title">Thông tin hộ dân</h5><button type="button" class="btn-close" data-bs-dismiss="modal" aria-label="Đóng"></button></div><div class="modal-body"><input type="hidden" name="id"><div class="row g-3"><div class="col-md-4"><label class="form-label">Mã hộ</label><input name="householdCode" class="form-control" required></div><div class="col-md-4"><label class="form-label">Tên chủ hộ</label><input name="headCitizenName" class="form-control" required></div><div class="col-md-4"><label class="form-label">Số điện thoại</label><input name="phone" class="form-control"></div><div class="col-12"><label class="form-label">Địa chỉ</label><input name="address" class="form-control" required></div><div class="col-md-3 form-check ms-2"><input name="meritoriousFamily" class="form-check-input" type="checkbox" id="meritoriousFamily"><label class="form-check-label" for="meritoriousFamily">Gia đình có công</label></div><div class="col-md-2 form-check"><input name="poorHousehold" class="form-check-input" type="checkbox" id="poorHousehold"><label class="form-check-label" for="poorHousehold">Hộ nghèo</label></div><div class="col-md-2 form-check"><input name="nearPoorHousehold" class="form-check-input" type="checkbox" id="nearPoorHousehold"><label class="form-check-label" for="nearPoorHousehold">Cận nghèo</label></div><div class="col-md-2 form-check"><input name="disabledHousehold" class="form-check-input" type="checkbox" id="disabledHousehold"><label class="form-check-label" for="disabledHousehold">Tàn tật</label></div><div class="col-12"><label class="form-label">Ảnh hộ</label><input name="householdPhoto" type="file" class="form-control" accept="image/*"></div><div class="col-12"><label class="form-label">Ghi chú</label><textarea name="note" class="form-control" rows="2"></textarea></div></div></div><div class="modal-footer"><button type="button" class="btn btn-light" data-bs-dismiss="modal">Hủy</button><button type="button" class="btn btn-outline-secondary" onclick="window.print()">In phiếu hộ</button><button type="submit" class="btn btn-primary">Lưu</button></div></form></div></div>

  <div class="modal fade" id="personModal" tabindex="-1" aria-hidden="true"><div class="modal-dialog modal-xl modal-dialog-scrollable"><form class="modal-content" id="personForm"><div class="modal-header"><h5 class="modal-title">Thông tin nhân khẩu</h5><button type="button" class="btn-close" data-bs-dismiss="modal" aria-label="Đóng"></button></div><div class="modal-body"><input type="hidden" name="id"><div class="row g-3"><div class="col-md-3"><label class="form-label">Mã hộ</label><input name="householdCode" class="form-control" required></div><div class="col-md-3"><label class="form-label">Mã nhân khẩu</label><input name="citizenCode" class="form-control"></div><div class="col-md-6"><label class="form-label">Họ và tên</label><input name="fullName" class="form-control" required></div><div class="col-md-3"><label class="form-label">Giới tính</label><select name="gender" class="form-select"><option>Nam</option><option>Nữ</option><option>Khác</option></select></div><div class="col-md-3"><label class="form-label">Ngày sinh</label><input name="dateOfBirth" type="date" class="form-control" required></div><div class="col-md-3"><label class="form-label">CCCD</label><input name="identityNumber" class="form-control"></div><div class="col-md-3"><label class="form-label">Số điện thoại</label><input name="phone" class="form-control"></div><div class="col-md-3"><label class="form-label">Quan hệ với chủ hộ</label><select name="relationship" class="form-select" data-options="relationships"></select></div><div class="col-md-3"><label class="form-label">Dân tộc</label><select name="ethnicity" class="form-select" data-options="ethnicities"></select></div><div class="col-md-3"><label class="form-label">Tôn giáo</label><select name="religion" class="form-select" data-options="religions"></select></div><div class="col-md-3"><label class="form-label">Nghề nghiệp</label><select name="occupation" class="form-select" data-options="occupations"></select></div><div class="col-md-3"><label cla